// TestFullScanWithFixtures tests a complete scan of a test fixture directory
func TestFullScanWithFixtures(t *testing.T) {
	ctx := context.Background()

	// Setup
	ds := &tests.MockDataStore{}
	ds.MockedMediaFile = tests.CreateMockMediaFileRepo()
	ds.MockedAlbum = tests.CreateMockAlbumRepo()
	ds.MockedArtist = tests.CreateMockArtistRepo()
	ds.MockedGenre = &tests.MockedGenreRepo{}

	mockPlaylists := &mockPlaylists{}
	mockCacheWarmer := &mockCacheWarmer{}
	mockBroker := &mockBroker{}

	fixtureDir := getFixturePath("artist/an-album")
	lib := model.Library{
		ID:         1,
		Path:       fixtureDir,
		LastScanAt: time.Time{}, // First scan
	}

	// Create scanner
	scanner := NewTagScanner(ds, mockPlaylists, mockCacheWarmer)

	// Execute scan
	progress := make(chan uint32, 100)
	changeCount, err := scanner.Scan(ctx, lib, true, progress)
	close(progress)

	// Assertions
	require.NoError(t, err, "scan should succeed")
	assert.Greater(t, changeCount, int64(0), "should detect at least one change")

	// Verify mediafiles were created
	mediaFiles, err := ds.MediaFile(ctx).GetAll()
	require.NoError(t, err)
	assert.Greater(t, len(mediaFiles), 0, "should create at least one mediafile")

	// Verify mediafile properties
	if len(mediaFiles) > 0 {
		mf := mediaFiles[0]
		assert.NotEmpty(t, mf.Title, "mediafile should have a title")
		assert.NotEmpty(t, mf.Path, "mediafile should have a path")
		assert.NotEmpty(t, mf.Album, "mediafile should have an album")
		assert.NotEmpty(t, mf.Artist, "mediafile should have an artist")
	}
}

// TestMetadataExtraction verifies that metadata is correctly extracted from audio files
func TestMetadataExtraction(t *testing.T) {
	ctx := context.Background()

	// Setup
	ds := &tests.MockDataStore{}
	ds.MockedMediaFile = tests.CreateMockMediaFileRepo()
	ds.MockedAlbum = tests.CreateMockAlbumRepo()
	ds.MockedArtist = tests.CreateMockArtistRepo()
	ds.MockedGenre = &tests.MockedGenreRepo{}

	mockPlaylists := &mockPlaylists{}
	mockCacheWarmer := &mockCacheWarmer{}

	fixtureDir := getFixturePath("artist/an-album")
	lib := model.Library{
		ID:         1,
		Path:       fixtureDir,
		LastScanAt: time.Time{},
	}

	scanner := NewTagScanner(ds, mockPlaylists, mockCacheWarmer)
	progress := make(chan uint32, 100)
	_, err := scanner.Scan(ctx, lib, true, progress)
	close(progress)

	require.NoError(t, err)

	mediaFiles, err := ds.MediaFile(ctx).GetAll()
	require.NoError(t, err)
	require.Greater(t, len(mediaFiles), 0, "should extract at least one track")

	// Verify metadata extraction
	mf := mediaFiles[0]
	assert.NotEmpty(t, mf.Title, "should extract title")
	assert.NotEmpty(t, mf.Album, "should extract album")
	assert.NotEmpty(t, mf.Artist, "should extract artist")
	assert.Greater(t, mf.TrackNumber, 0, "should extract track number")
	assert.NotEmpty(t, mf.Suffix, "should extract file suffix")
	assert.Greater(t, mf.Duration, float32(0), "should extract duration")
	assert.NotEmpty(t, mf.Path, "should store file path")
}

// TestAlbumAndArtistCreation verifies that albums and artists are created during scan
func TestAlbumAndArtistCreation(t *testing.T) {
	ctx := context.Background()

	// Setup
	ds := &tests.MockDataStore{}
	ds.MockedMediaFile = tests.CreateMockMediaFileRepo()
	ds.MockedAlbum = tests.CreateMockAlbumRepo()
	ds.MockedArtist = tests.CreateMockArtistRepo()
	ds.MockedGenre = &tests.MockedGenreRepo{}

	mockPlaylists := &mockPlaylists{}
	mockCacheWarmer := &mockCacheWarmer{}

	fixtureDir := getFixturePath("artist/an-album")
	lib := model.Library{
		ID:         1,
		Path:       fixtureDir,
		LastScanAt: time.Time{},
	}

	scanner := NewTagScanner(ds, mockPlaylists, mockCacheWarmer)
	progress := make(chan uint32, 100)
	_, err := scanner.Scan(ctx, lib, true, progress)
	close(progress)

	require.NoError(t, err)

	// Verify mediafiles
	mediaFiles, err := ds.MediaFile(ctx).GetAll()
	require.NoError(t, err)
	require.Greater(t, len(mediaFiles), 0, "should create mediafiles")

	// Extract unique album and artist IDs
	albumIDs := make(map[string]bool)
	artistIDs := make(map[string]bool)
	albumArtistIDs := make(map[string]bool)

	for _, mf := range mediaFiles {
		albumIDs[mf.AlbumID] = true
		artistIDs[mf.ArtistID] = true
		albumArtistIDs[mf.AlbumArtistID] = true
	}

	assert.Greater(t, len(albumIDs), 0, "should create albums")
	assert.Greater(t, len(artistIDs), 0, "should create artists")
	assert.Greater(t, len(albumArtistIDs), 0, "should create album artists")
}

// TestIncrementalScan verifies that re-scanning without changes produces no DB updates
func TestIncrementalScan(t *testing.T) {
	ctx := context.Background()

	// Setup
	ds := &tests.MockDataStore{}
	ds.MockedMediaFile = tests.CreateMockMediaFileRepo()
	ds.MockedAlbum = tests.CreateMockAlbumRepo()
	ds.MockedArtist = tests.CreateMockArtistRepo()
	ds.MockedGenre = &tests.MockedGenreRepo{}

	mockPlaylists := &mockPlaylists{}
	mockCacheWarmer := &mockCacheWarmer{}

	fixtureDir := getFixturePath("artist/an-album")

	// First scan
	lib := model.Library{
		ID:         1,
		Path:       fixtureDir,
		LastScanAt: time.Time{},
	}

	scanner := NewTagScanner(ds, mockPlaylists, mockCacheWarmer)
	progress := make(chan uint32, 100)
	firstChangeCount, err := scanner.Scan(ctx, lib, true, progress)
	close(progress)

	require.NoError(t, err)
	assert.Greater(t, firstChangeCount, int64(0), "first scan should detect changes")

	// Get the updated timestamp from first scan
	mediaFiles, err := ds.MediaFile(ctx).GetAll()
	require.NoError(t, err)
	require.Greater(t, len(mediaFiles), 0)

	// Update library's last scan time to just after the file modification time
	lib.LastScanAt = time.Now()

	// Second scan (incremental)
	scanner2 := NewTagScanner(ds, mockPlaylists, mockCacheWarmer)
	progress2 := make(chan uint32, 100)
	secondChangeCount, err := scanner2.Scan(ctx, lib, false, progress2)
	close(progress2)

	require.NoError(t, err)
	assert.Equal(t, int64(0), secondChangeCount, "incremental scan should find no changes when files unchanged")
}

// TestMediaFileIDGeneration verifies that media files have consistent IDs
func TestMediaFileIDGeneration(t *testing.T) {
	ctx := context.Background()

	// Setup
	ds := &tests.MockDataStore{}
	ds.MockedMediaFile = tests.CreateMockMediaFileRepo()
	ds.MockedAlbum = tests.CreateMockAlbumRepo()
	ds.MockedArtist = tests.CreateMockArtistRepo()
	ds.MockedGenre = &tests.MockedGenreRepo{}

	mockPlaylists := &mockPlaylists{}
	mockCacheWarmer := &mockCacheWarmer{}

	fixtureDir := getFixturePath("artist/an-album")
	lib := model.Library{
		ID:         1,
		Path:       fixtureDir,
		LastScanAt: time.Time{},
	}

	scanner := NewTagScanner(ds, mockPlaylists, mockCacheWarmer)
	progress := make(chan uint32, 100)
	_, err := scanner.Scan(ctx, lib, true, progress)
	close(progress)

	require.NoError(t, err)

	mediaFiles1, err := ds.MediaFile(ctx).GetAll()
	require.NoError(t, err)
	require.Greater(t, len(mediaFiles1), 0)

	// Clear and rescan
	ds.MockedMediaFile = tests.CreateMockMediaFileRepo()
	ds.MockedAlbum = tests.CreateMockAlbumRepo()
	ds.MockedGenre = &tests.MockedGenreRepo{}

	scanner2 := NewTagScanner(ds, mockPlaylists, mockCacheWarmer)
	progress2 := make(chan uint32, 100)
	_, err = scanner2.Scan(ctx, lib, true, progress2)
	close(progress2)

	require.NoError(t, err)

	mediaFiles2, err := ds.MediaFile(ctx).GetAll()
	require.NoError(t, err)
	require.Greater(t, len(mediaFiles2), 0)

	// Verify IDs are consistent
	assert.Equal(t, mediaFiles1[0].ID, mediaFiles2[0].ID, "media file IDs should be deterministic")
}

// TestMultipleTracksInDirectory verifies scanner handles multiple tracks correctly
func TestMultipleTracksInDirectory(t *testing.T) {
	ctx := context.Background()

	// Setup
	ds := &tests.MockDataStore{}
	ds.MockedMediaFile = tests.CreateMockMediaFileRepo()
	ds.MockedAlbum = tests.CreateMockAlbumRepo()
	ds.MockedArtist = tests.CreateMockArtistRepo()
	ds.MockedGenre = &tests.MockedGenreRepo{}

	mockPlaylists := &mockPlaylists{}
	mockCacheWarmer := &mockCacheWarmer{}

	// Use fixtures root which has multiple files
	fixtureDir := getFixturePath(".")
	lib := model.Library{
		ID:         1,
		Path:       fixtureDir,
		LastScanAt: time.Time{},
	}

	scanner := NewTagScanner(ds, mockPlaylists, mockCacheWarmer)
	progress := make(chan uint32, 100)
	changeCount, err := scanner.Scan(ctx, lib, true, progress)
	close(progress)

	require.NoError(t, err, "scan should succeed with multiple files")

	mediaFiles, err := ds.MediaFile(ctx).GetAll()
	require.NoError(t, err)

	// Should have found multiple audio files
	assert.Greater(t, len(mediaFiles), 1, "should find multiple audio files")
	assert.Greater(t, changeCount, int64(1), "should report multiple changes")

	// Verify each file has a path
	for _, mf := range mediaFiles {
		assert.NotEmpty(t, mf.Path, "each mediafile should have a path")
		assert.NotEmpty(t, mf.ID, "each mediafile should have an ID")
	}
}

