// TestTrackNumberExtraction verifies track number is extracted correctly
func TestTrackNumberExtraction(t *testing.T) {
	ctx := context.Background()

	// Setup
	ds := &tests.MockDataStore{}
	ds.MockedMediaFile = tests.CreateMockMediaFileRepo()
	ds.MockedAlbum = tests.CreateMockAlbumRepo()
	ds.MockedArtist = tests.CreateMockArtistRepo()
	ds.MockedGenre = &tests.MockedGenreRepo{}

