// TestFilePathPreservation verifies that file paths are correctly preserved
func TestFilePathPreservation(t *testing.T) {
	ctx := context.Background()

	// Setup
	ds := &tests.MockDataStore{}
	ds.MockedMediaFile = tests.CreateMockMediaFileRepo()
	ds.MockedAlbum = tests.CreateMockAlbumRepo()
	ds.MockedArtist = tests.CreateMockArtistRepo()
	ds.MockedGenre = &tests.MockedGenreRepo{}

	mockPlaylists := &mockPlaylists{}
	mockCacheWarmer := &mockCacheWarmer{}

	fixtureDir := getFixturePath("artist/an-album")
	lib := model.Library{
		ID:         1,
		Path:       fixtureDir,
		LastScanAt: time.Time{},
	}

	scanner := NewTagScanner(ds, mockPlaylists, mockCacheWarmer)
	progress := make(chan uint32, 100)
	_, err := scanner.Scan(ctx, lib, true, progress)
	close(progress)

	require.NoError(t, err)

	mediaFiles, err := ds.MediaFile(ctx).GetAll()
	require.NoError(t, err)
	require.Greater(t, len(mediaFiles), 0)

	// Verify paths are absolute and point to files that exist or existed
	for _, mf := range mediaFiles {
		assert.True(t, filepath.IsAbs(mf.Path), "media file path should be absolute")
		assert.True(t, filepath.Dir(mf.Path) == fixtureDir, "media file path should be in fixture directory")
	}
}

