   119→func (s *scanner) startProgressTracker(library string) (chan uint32, context.CancelFunc) {
   120→	// Must be a new context (not the one passed to the scan method) to allow broadcasting the scan status to all clients
   121→	ctx, cancel := context.WithCancel(context.Background())
   122→	progress := make(chan uint32, 1000)
   123→	limiter := rate.Sometimes{Interval: conf.Server.DevActivityPanelUpdateRate}
   124→	go func() {
   125→		s.broker.SendMessage(ctx, &events.ScanStatus{Scanning: true, Count: 0, FolderCount: 0})
   126→		defer func() {
   127→			if status, ok := s.getStatus(library); ok {
   128→				s.broker.SendMessage(ctx, &events.ScanStatus{
   129→					Scanning:    false,
   130→					Count:       int64(status.fileCount),
   131→					FolderCount: int64(status.folderCount),
   132→				})
   133→			}
   134→		}()
   135→		for {
   136→			select {
   137→			case <-ctx.Done():
   138→				return
   139→			case count := <-progress:
   140→				if count == 0 {
   141→					continue
   142→				}
   143→				totalFolders, totalFiles := s.incStatusCounter(library, count)
   144→				limiter.Do(func() {
   145→					s.broker.SendMessage(ctx, &events.ScanStatus{
   146→						Scanning:    true,
   147→						Count:       int64(totalFiles),
   148→						FolderCount: int64(totalFolders),
   149→					})
   150→				})
   151→			}
   152→		}
   153→	}()
   154→	return progress, cancel
   155→}
