   163→		// Now that all mediafiles are imported/updated, search for and import/update playlists
   164→		u, _ := request.UserFrom(ctx)
   165→		for _, dir := range changedDirs {
   166→			info := allFSDirs[dir]
   167→			if info.HasPlaylist {
   168→				if !u.IsAdmin {
   169→					log.Warn("Playlists will not be imported, as there are no admin users yet, "+
   170→						"Please create an admin user first, and then update the playlists for them to be imported", "dir", dir)
   171→				} else {
   172→					plsSync := newPlaylistImporter(s.ds, s.playlists, s.cacheWarmer, lib.Path)
