   405→func (s *TagScanner) loadTracks(filePaths []string) (model.MediaFiles, error) {
   406→	mds, err := metadata.Extract(filePaths...)
   407→	if err != nil {
   408→		return nil, err
   409→	}
   410→
   411→	var mfs model.MediaFiles
   412→	for _, md := range mds {
   413→		mf := s.mapper.ToMediaFile(md)
   414→		mfs = append(mfs, mf)
   415→	}
   416→	return mfs, nil
   417→}
