   275→func (t Tags) getPeakValue(tagName string) float64 {
   276→	var tag = t.getFirstTagValue(tagName)
   277→	var value, err = strconv.ParseFloat(tag, 64)
   278→	if err != nil || value == math.Inf(-1) || value == math.Inf(1) {
   279→		// A default of 1 for peak value results in no changes
   280→		return 1
   281→	}
   282→	return value
   283→}
