   369→func (t Tags) getTuple(tagNames ...string) (int, int) {
   370→	tag := t.getFirstTagValue(tagNames...)
   371→	if tag == "" {
   372→		return 0, 0
   373→	}
   374→	tuple := strings.Split(tag, "/")
   375→	t1, t2 := 0, 0
   376→	t1, _ = strconv.Atoi(tuple[0])
   377→	if len(tuple) > 1 {
   378→		t2, _ = strconv.Atoi(tuple[1])
   379→	} else {
   380→		t2tag := t.getFirstTagValue(tagNames[0] + "total")
   381→		t2, _ = strconv.Atoi(t2tag)
   382→	}
   383→	return t1, t2
   384→}
