	progress := make(chan uint32, 100)
	_, err := scanner.Scan(ctx, lib, true, progress)
	close(progress)

	require.NoError(t, err)

	mediaFiles, err := ds.MediaFile(ctx).GetAll()
	require.NoError(t, err)
	require.Greater(t, len(mediaFiles), 0)

	// Genre extraction may vary depending on file metadata
	// But genres slice should be populated if available
	for _, mf := range mediaFiles {
		if mf.Genre != "" {
			assert.Greater(t, len(mf.Genres), 0, "if genre is set, genres list should be populated")
		}
	}
}

// TestLibraryIDAssignment verifies that all mediafiles are assigned the correct library ID
func TestLibraryIDAssignment(t *testing.T) {
	ctx := context.Background()

	// Setup
